public PurchCopyingContract getPurchCopyingContract()
{
    PurchCopyingContract contract = next getPurchCopyingContract();

    contract.parmCopyHeaderTextBlock(this.parmCopyHeaderTextBlock());
    contract.parmCopyLineTextBlock(this.parmCopyLineTextBlock());

    return contract;
}

public NoYes parmCopyHeaderTextBlock(NoYes _copyHeaderTB = copyHeaderTB)
{
    copyHeaderTB = _copyHeaderTB;
    return copyHeaderTB;
}

public NoYes parmCopyLineTextBlock(NoYes _copyLineTB = copyLineTB)
{
    copyLineTB = _copyLineTB;
    return copyLineTB;
}
